package be.schaubroeck.lpb.rkm.rekenmotor.check;

import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonCodeManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.PersoonsDataManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.NlpPrestatie;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.enumtypes.AardKodeExt;
import be.schaubroeck.lpb.tools.enumtypes.KedefFormuletype;
import be.schaubroeck.lpb.tools.enumtypes.RekenControleCode;
import be.schaubroeck.lpb.tools.enumtypes.Tellerkode;
import com.google.common.collect.HashMultimap;
import com.google.common.collect.Multimap;
import lombok.AllArgsConstructor;
import lombok.Value;
import org.joda.time.LocalDate;

import java.util.Collection;
import java.util.List;
import java.util.Set;

@AllArgsConstructor
public class CheckDubbelePrestaties {

    private final RegulManager regulManager;
    private final LoonCodeManager loonCodeManager;
    private final PersoonsDataManager dataManager;

    public void check(Persoon persoon, RekenTijd rekenTijd) {
        Set<Opdracht> opdrachten = persoon.getOpdrachten();
        for (Opdracht opdracht : opdrachten) {
            checkOpdracht(opdracht, rekenTijd);
        }
    }

    private void checkOpdracht(Opdracht opdracht, RekenTijd rekenTijd) {
        List<NlpPrestatie> prestaties = dataManager.findPrestaties(opdracht, rekenTijd.eindDatum);
        Multimap<PrestatieKey, NlpPrestatie> dubbelsMap = HashMultimap.create();
        for (NlpPrestatie prestatie : prestaties) {
            PrestatieKey prestatieKey = new PrestatieKey(prestatie);
            boolean isDubbel = checkVoorDubbels(opdracht, prestatie, prestatieKey, dubbelsMap);
            if (!isDubbel) {
                dubbelsMap.put(prestatieKey, prestatie);
            }
        }
    }

    private boolean checkVoorDubbels(Opdracht opdracht, NlpPrestatie prestatie, PrestatieKey prestatieKey, Multimap<PrestatieKey, NlpPrestatie> dubbelsMap) {
        Collection<NlpPrestatie> lijst = dubbelsMap.get(prestatieKey);
        AardKodeExt aard = AardKodeExt.getByCode(prestatie.getAard());
        for (NlpPrestatie dubbel : lijst) {
            if (aard == AardKodeExt.I_KODE_EXT || aard == AardKodeExt.S_KODE_EXT) {
                return isDubbelSupplementOfInhouding(opdracht, prestatie, dubbel);
            } else if (aard == AardKodeExt.D_KODE_EXT) {
                return isDubbelDagCode(opdracht, prestatie, dubbel);
            } else if (aard == AardKodeExt.K_KODE_EXT) {
                return isDubbelKalenderCode(opdracht, prestatie, dubbel);
            } else {
                return false;
            }
        }
        return false;
    }

    private boolean isDubbelDagCode(Opdracht opdracht, NlpPrestatie prestatie, NlpPrestatie dubbel) {
        AardKodeExtensie ake = loonCodeManager.getByPrestatie(prestatie);
        boolean isDubbel = (ake.getTellerCode() == Tellerkode.DS && prestatie.getY().compareTo(dubbel.getY()) == 0) ||
                (ake.getTellerCode() != Tellerkode.DS && prestatie.getAantal().compareTo(dubbel.getAantal()) == 0);
        if (isDubbel) {
            String omschrijving = getInfoString(prestatie);
            if (ake.getTellerCode() == Tellerkode.DS) {
                omschrijving += " met y=" + prestatie.getY().getAmount();
            } else {
                omschrijving += " met aantal=" + prestatie.getAantal();
            }
            regulManager.addProtoWaarschuwing(opdracht, RekenControleCode.DUBBELE_PRESTATIES, omschrijving);
        }
        return isDubbel;
    }

    private boolean isDubbelKalenderCode(Opdracht opdracht, NlpPrestatie prestatie, NlpPrestatie dubbel) {
        boolean isDubbel = prestatie.getAantal().compareTo(dubbel.getAantal()) == 0;
        if (isDubbel) {
            String omschrijving = getInfoString(prestatie) + " met aantal=" + prestatie.getAantal();
            regulManager.addProtoWaarschuwing(opdracht, RekenControleCode.DUBBELE_PRESTATIES, omschrijving);
        }
        return isDubbel;
    }

    private boolean isDubbelSupplementOfInhouding(Opdracht opdracht, NlpPrestatie prestatie1, NlpPrestatie prestatie2) {
        AardKodeExtensie ake = loonCodeManager.getByPrestatie(prestatie1);
        boolean isDubbel = ake.getFormuleType() != KedefFormuletype.ONR_XxY || prestatie1.getY().compareTo(prestatie2.getY()) == 0;
        if (isDubbel) {
            String omschrijving = getInfoString(prestatie1) + " met y=" + prestatie1.getY().getAmount();
            regulManager.addProtoWaarschuwing(opdracht, RekenControleCode.DUBBELE_PRESTATIES, omschrijving);
        }
        return isDubbel;
    }

    private String getInfoString(NlpPrestatie prestatie) {
        return "Dubbele prestatie " + prestatie.getAard() + "-" + prestatie.getCode() + "-" + prestatie.getExtensie() + " op " + prestatie.getDatum();
    }

    @Value
    private static class PrestatieKey {
        LocalDate datum;
        Integer tijdperk;
        Integer aard;
        Integer code;
        Integer extensie;

        public PrestatieKey(NlpPrestatie prestatie) {
            this.datum = prestatie.getDatum();
            this.tijdperk = prestatie.getTijdperk();
            this.aard = prestatie.getAard();
            this.code = prestatie.getCode();
            this.extensie = prestatie.getExtensie();
        }
    }
}
